const payload = ($input.first().json.payload ?? $input.first().json);
const dangerous = ['activate_workflow', 'deactivate_workflow', 'create_workflow'];
if (!payload.action) return [{ json: { status: 'error', result: {}, error: 'action is required' } }];
if (dangerous.includes(payload.action)) return [{ json: { status: 'pending_approval', result: { workflow_id: payload.workflow_id, action: payload.action, backup_required: true }, approval_required: true } }];
return [{ json: { status: 'success', result: { action: payload.action, workflow_id: payload.workflow_id ?? null, description: payload.description ?? null, note: 'Documentation/audit mode only in V1 draft.' } } }];
